import threading
store = InMemoryStore()
def writer(i):
    store.create(f'key{i}', i)
threads = [threading.Thread(target=writer, args=(i,)) for i in range(100)]
for t in threads: t.start()
for t in threads: t.join()
assert store.count() == 100
